import{_ as l,o as e,c as i,a2 as t}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"市場情緒日報 — 2026年5月4日","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/市場情緒/市場情緒_20260504.md","filePath":"Deep32Q知識庫/市場情緒/市場情緒_20260504.md"}'),r={name:"Deep32Q知識庫/市場情緒/市場情緒_20260504.md"};function o(n,a,h,s,d,u){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="市場情緒日報-—-2026年5月4日" tabindex="-1">市場情緒日報 — 2026年5月4日 <a class="header-anchor" href="#市場情緒日報-—-2026年5月4日" aria-label="Permalink to &quot;市場情緒日報 — 2026年5月4日&quot;">​</a></h1><h2 id="📌-全球財經頭條重點-10點" tabindex="-1">📌 全球財經頭條重點（10點） <a class="header-anchor" href="#📌-全球財經頭條重點-10點" aria-label="Permalink to &quot;📌 全球財經頭條重點（10點）&quot;">​</a></h2><h3 id="_1-s-p-500-創歷史新高-突破-7-200-點" tabindex="-1">1. S&amp;P 500 創歷史新高，突破 7,200 點 <a class="header-anchor" href="#_1-s-p-500-創歷史新高-突破-7-200-點" aria-label="Permalink to &quot;1. S&amp;P 500 創歷史新高，突破 7,200 點&quot;">​</a></h3><ul><li>美股 S&amp;P 500 於 5/1 首次收盤突破 7,200 點，創歷史新高。主要驱动力為 Alphabet 強勁財報及 Apple 宣布 1,000 億美元股票回購計畫。</li><li><strong>來源</strong>：ATB Wealth (2026-05-04)</li></ul><h3 id="_2-apple-1-000-億美元回購-股價漲-3" tabindex="-1">2. Apple 1,000 億美元回購，股價漲 3% <a class="header-anchor" href="#_2-apple-1-000-億美元回購-股價漲-3" aria-label="Permalink to &quot;2. Apple 1,000 億美元回購，股價漲 3%&quot;">​</a></h3><ul><li>Apple 宣布 1,000 億美元股票回購，營收成長達 17%，推動 S&amp;P 500 創新高。</li><li><strong>來源</strong>：247WallSt (2026-05-03)</li></ul><h3 id="_3-microsoft-財報遜預期-股價跌-4" tabindex="-1">3. Microsoft 財報遜預期，股價跌 4% <a class="header-anchor" href="#_3-microsoft-財報遜預期-股價跌-4" aria-label="Permalink to &quot;3. Microsoft 財報遜預期，股價跌 4%&quot;">​</a></h3><ul><li>Microsoft 營收及營業利潤率前瞻低於市場預期，儘管雲端成長強勁，股價仍下跌 4%。</li><li><strong>來源</strong>：ATB Wealth (2026-05-04)</li></ul><h3 id="_4-meta-資本支出引擔憂-股價暴跌近-9" tabindex="-1">4. Meta 資本支出引擔憂，股價暴跌近 9% <a class="header-anchor" href="#_4-meta-資本支出引擔憂-股價暴跌近-9" aria-label="Permalink to &quot;4. Meta 資本支出引擔憂，股價暴跌近 9%&quot;">​</a></h3><ul><li>Meta 宣布大幅增加 AI 基礎設施資本支出，但市場質疑短期無法帶來顯著成長收益，公司需發行更多債務。</li><li><strong>來源</strong>：ATB Wealth (2026-05-04)</li></ul><h3 id="_5-中東戰事推升原油價格" tabindex="-1">5. 中東戰事推升原油價格 <a class="header-anchor" href="#_5-中東戰事推升原油價格" aria-label="Permalink to &quot;5. 中東戰事推升原油價格&quot;">​</a></h3><ul><li>伊朗戰爭導致 WTI 原油飆至 110 美元/桶，Brent 原油區間 114-126 美元。霍爾木茲海峽實質封鎖，全球通膨壓力升溫。</li><li><strong>來源</strong>：ATB Wealth (2026-05-04)</li></ul><h3 id="_6-聯準會領導層交接" tabindex="-1">6. 聯準會領導層交接 <a class="header-anchor" href="#_6-聯準會領導層交接" aria-label="Permalink to &quot;6. 聯準會領導層交接&quot;">​</a></h3><ul><li>Powell 任期於 5/15 結束，Trump 提名的 Kevin Warsh 已通過參議院銀行委員會審查。Fed 維持利率 3.5%-3.75% 不變。</li><li><strong>來源</strong>：ATB Wealth (2026-05-04), CryptoBriefing (2026-05-02)</li></ul><h3 id="_7-比特幣突破-70-000-美元-etf-持續吸金" tabindex="-1">7. 比特幣突破 70,000 美元，ETF 持續吸金 <a class="header-anchor" href="#_7-比特幣突破-70-000-美元-etf-持續吸金" aria-label="Permalink to &quot;7. 比特幣突破 70,000 美元，ETF 持續吸金&quot;">​</a></h3><ul><li>比特幣 4 月收於 $76,110，5 月初交易於 $70,000 以上。Spot Bitcoin ETF 單日淨流入達 $6.298 億，BlackRock IBIT 佔 $2.844 億。</li><li><strong>來源</strong>：ATB Wealth (2026-05-04), CryptoBriefing (2026-05-02)</li></ul><h3 id="_8-阿聯脫離-opec-5-1-生效" tabindex="-1">8. 阿聯脫離 OPEC（5/1 生效） <a class="header-anchor" href="#_8-阿聯脫離-opec-5-1-生效" aria-label="Permalink to &quot;8. 阿聯脫離 OPEC（5/1 生效）&quot;">​</a></h3><ul><li>阿拉伯聯合大公國宣布自 2026年5月1日起退出 OPEC，對全球油市供應格局產生重大影響。</li><li><strong>來源</strong>：ATB Wealth (2026-05-04)</li></ul><h3 id="_9-新興市場承壓-印度盧比創歷史新低" tabindex="-1">9. 新興市場承壓，印度盧比創歷史新低 <a class="header-anchor" href="#_9-新興市場承壓-印度盧比創歷史新低" aria-label="Permalink to &quot;9. 新興市場承壓，印度盧比創歷史新低&quot;">​</a></h3><ul><li>印度盧比貶至 95.33/美元，創歷史新低。外資持續淨賣出，但內資部分抵消跌勢。</li><li><strong>來源</strong>：ATB Wealth (2026-05-04), GoodReturns (2026-05-04)</li></ul><h3 id="_10-全球央行維持利率不變" tabindex="-1">10. 全球央行維持利率不變 <a class="header-anchor" href="#_10-全球央行維持利率不變" aria-label="Permalink to &quot;10. 全球央行維持利率不變&quot;">​</a></h3><ul><li>英國央行維持 3.75%、日本央行、歐銀均維持利率不變。澳洲儲備銀行 5/4 預期升息 25 基碼。菲律賓央行已升息 25 基碼並預警通膨。</li><li><strong>來源</strong>：ATB Wealth (2026-05-04), OurMidland (2026-05-04)</li></ul><hr><h2 id="🇹🇼-台灣財經重點摘要" tabindex="-1">🇹🇼 台灣財經重點摘要 <a class="header-anchor" href="#🇹🇼-台灣財經重點摘要" aria-label="Permalink to &quot;🇹🇼 台灣財經重點摘要&quot;">​</a></h2><h3 id="_1-台股-4-月狂飆-7-203-點-5-3-收-38-926-63" tabindex="-1">1. 台股 4 月狂飆 7,203 點，5/3 收 38,926.63 <a class="header-anchor" href="#_1-台股-4-月狂飆-7-203-點-5-3-收-38-926-63" aria-label="Permalink to &quot;1. 台股 4 月狂飆 7,203 點，5/3 收 38,926.63&quot;">​</a></h3><ul><li>加權指數 4 月暴漲，兩度突破 40,000 點。5/3 收盤 38,926.63（-0.96%），短線震盪整理。</li><li><strong>來源</strong>：udn Money (2026-05), CNYes (2026-05)</li></ul><h3 id="_2-法人看-5-月五大利多-目標挑戰-41-000" tabindex="-1">2. 法人看 5 月五大利多，目標挑戰 41,000 <a class="header-anchor" href="#_2-法人看-5-月五大利多-目標挑戰-41-000" aria-label="Permalink to &quot;2. 法人看 5 月五大利多，目標挑戰 41,000&quot;">​</a></h3><ul><li>上市櫃 Q1 獲利預期 1.5 兆元、Davis 雙擊效應、ETF 資金持續流入、「520行情」歷史勝率高（近八成）、6 月 Computex AI 題材。</li><li><strong>來源</strong>：udn Money (2026-05), CNYes (2026-05)</li></ul><h3 id="_3-外資-4-月買超-2-481-億-5-月轉保守" tabindex="-1">3. 外資 4 月買超 2,481 億，5 月轉保守 <a class="header-anchor" href="#_3-外資-4-月買超-2-481-億-5-月轉保守" aria-label="Permalink to &quot;3. 外資 4 月買超 2,481 億，5 月轉保守&quot;">​</a></h3><ul><li>外資 4 月創歷史買超紀錄。但 5 月初連續 4 天賣超，累計賣超 1,922 億。台積電遭賣超 1,734 億為最大賣點。</li><li><strong>來源</strong>：CNYes (2026-05), WantGo (2026-05)</li></ul><h3 id="_4-投信持續買超-布局個股" tabindex="-1">4. 投信持續買超，布局個股 <a class="header-anchor" href="#_4-投信持續買超-布局個股" aria-label="Permalink to &quot;4. 投信持續買超，布局個股&quot;">​</a></h3><ul><li>投信 4/29 集中市場買超 22.33 億、櫃買買超 2.53 億。鎖定台積電、華邦電、富喬等低本益比個股。</li><li><strong>來源</strong>：CNYes (2026-05), Sinotrade (2026-05)</li></ul><h3 id="_5-新台幣匯率波動-usd-twd-約-31-57-31-72" tabindex="-1">5. 新台幣匯率波動，USD/TWD 約 31.57-31.72 <a class="header-anchor" href="#_5-新台幣匯率波動-usd-twd-約-31-57-31-72" aria-label="Permalink to &quot;5. 新台幣匯率波動，USD/TWD 約 31.57-31.72&quot;">​</a></h3><ul><li>5/1 USD/TWD 升至 31.63。過去 12 個月台幣貶值 2.96%。央行持續調節匯率，並要求外資資金進場。</li><li><strong>來源</strong>：TradingEconomics (2026-05), Bank of Taiwan Rate (2026-05)</li></ul><h3 id="_6-台灣-q1-gdp-成長-13-7-創-1987-年來最高" tabindex="-1">6. 台灣 Q1 GDP 成長 13.7%，創 1987 年來最高 <a class="header-anchor" href="#_6-台灣-q1-gdp-成長-13-7-創-1987-年來最高" aria-label="Permalink to &quot;6. 台灣 Q1 GDP 成長 13.7%，創 1987 年來最高&quot;">​</a></h3><ul><li>受 AI 產品需求、出口、投資及民間消費帶動。UBS 上修 2026 年台灣 GDP 預測至 8%。</li><li><strong>來源</strong>：Japan Times (2026-05-01), Investing.com (2026-05)</li></ul><h3 id="_7-goldman-sachs-上調台股目標至-40-000" tabindex="-1">7. Goldman Sachs 上調台股目標至 40,000 <a class="header-anchor" href="#_7-goldman-sachs-上調台股目標至-40-000" aria-label="Permalink to &quot;7. Goldman Sachs 上調台股目標至 40,000&quot;">​</a></h3><ul><li>基於 AI 基礎設施支出帶動的強勁獲利預測，GS 將台股 12 個月目標從 36,000 上調至 40,000。</li><li><strong>來源</strong>：Investing.com (2026-05)</li></ul><h3 id="_8-台灣立法委員提案將外匯存底部分轉為比特幣" tabindex="-1">8. 台灣立法委員提案將外匯存底部分轉為比特幣 <a class="header-anchor" href="#_8-台灣立法委員提案將外匯存底部分轉為比特幣" aria-label="Permalink to &quot;8. 台灣立法委員提案將外匯存底部分轉為比特幣&quot;">​</a></h3><ul><li>台灣外匯存底約 6,020 億美元，80% 以上為美元。有立委提案部分轉為比特幣以分散美元風險。央行正測試扣押比特幣的沙盒環境。</li><li><strong>來源</strong>：CoinPedia (2026-05), Bitcoin.com (2026-05), CryptoBriefing (2026-05)</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>ATB Wealth Weekly Market Update (2026-05-04): 全球股市、原油、央行利率</li><li>247WallSt (2026-05-03): S&amp;P 500 創新高、Apple 回購</li><li>CryptoBriefing (2026-05-02): 比特幣價格、Fed 領導交接</li><li>udn Money (2026-05): 台股走勢、外資動向</li><li>CNYes (2026-05): 投信買超、法人展望</li><li>Japan Times (2026-05-01): 台灣 Q1 GDP 成長 13.7%</li><li>TradingEconomics (2026-05): 台幣匯率、台股指數</li><li>CoinPedia (2026-05): 台灣比特幣外匯存底提案</li></ol>',43)])])}const m=l(r,[["render",o]]);export{_ as __pageData,m as default};
